#include <bits/stdc++.h>
using namespace std;
int c[7];
int main()
{
    int a[7],k,d=0;
    cin>>k;
    int b[k][7];
    for(int i=0;i<=6;i++)
        {
            cin>>a[i];
        }
    for(int i=0;i<k;i++)
        {
            d=0;
            for(int j=0;j<7;j++)
                {
                    cin>>b[i][j];
                    for(int g=0;g<7;g++)
                        {
                            if(b[i][j]==a[g])
                            {
                                d+=1;
                                break;
                            }
                        }
                }
            if(d!=0)
            {
                c[7-d]+=1;
            }
        }
    for(int i=0;i<7;i++)
        {
            cout<<c[i]<<" ";
        }
    return 0;
}
